/* ── BOOKINGS PANEL ── */
function filterAdminBookings(filter, btn){
  _adminBookingFilter = filter;
  document.querySelectorAll('.booking-filter-btn').forEach(function(b){ b.classList.remove('active'); });
  btn.classList.add('active');
  renderAdminBookings();
}

function renderAdminBookings(){
  const url = _adminBookingFilter === 'all'
    ? '/api/admin/bookings'
    : '/api/admin/bookings?status=' + _adminBookingFilter;

  fetch(url)
  .then(r => r.json())
  .then(bs => {
    document.getElementById('bookingsCount').textContent = '(' + bs.length + ')';

    if(!bs.length){
      document.getElementById('adminBookingsBody').innerHTML =
        '<tr><td colspan="6" style="text-align:center;color:var(--muted);padding:28px">No bookings found.</td></tr>';
      return;
    }

    document.getElementById('adminBookingsBody').innerHTML = bs.map(function(b){
      var actions = '';
      if(b.status === 'pending'){
        actions = '<button class="action-approve" onclick="adminSetBookingStatus('+b.id+',\'approved\')">Approve</button>'+
                  '<button class="action-reject"  onclick="adminSetBookingStatus('+b.id+',\'rejected\')">Reject</button>';
      } else if(b.status === 'approved'){
        actions = '<button class="action-reject" onclick="adminSetBookingStatus('+b.id+',\'rejected\')">Reject</button>';
      } else if(b.status === 'rejected'){
        actions = '<button class="action-approve" onclick="adminSetBookingStatus('+b.id+',\'approved\')">Approve</button>';
      } else {
        actions = '<span style="color:var(--muted);font-size:11px">—</span>';
      }
      return '<tr>'+
        '<td><span class="tbl-name">'+b.facility_name+'</span></td>'+
        '<td><div class="tbl-name">'+b.user_name+'</div><div class="tbl-sub">'+b.user_email+'</div></td>'+
        '<td><div>'+b.start_time+'</div></td>'+
        '<td>'+b.end_time+'</td>'+
        '<td><span class="status-badge '+b.status+'">'+b.status+'</span></td>'+
        '<td>'+actions+'</td>'+
      '</tr>';
    }).join('');
  })
  .catch(() => {
    document.getElementById('adminBookingsBody').innerHTML =
      '<tr><td colspan="6" style="text-align:center;color:var(--muted);padding:28px">Could not load bookings.</td></tr>';
  });
}

  document.getElementById('adminBookingsBody').innerHTML = filtered.map(function(b){
    var actions = '';
    if(b.status==='pending'){
      actions = '<button class="action-approve" onclick="adminSetBookingStatus(\'' + b.id + '\',\'confirmed\')">Approve</button>'+
                '<button class="action-reject"  onclick="adminSetBookingStatus(\'' + b.id + '\',\'rejected\')">Reject</button>';
    } else if(b.status==='confirmed'){
      actions = '<button class="action-reject" onclick="adminSetBookingStatus(\'' + b.id + '\',\'rejected\')">Reject</button>';
    } else if(b.status==='rejected'){
      actions = '<button class="action-approve" onclick="adminSetBookingStatus(\'' + b.id + '\',\'confirmed\')">Approve</button>';
    } else {
      actions = '<span style="color:var(--muted);font-size:11px">—</span>';
    }
    return '<tr>'+
      '<td><div style="display:flex;align-items:center;gap:8px"><img src="'+(FACILITIES.find(function(x){return x.id===b.facilityId;})||{}).img+'"  style="width:36px;height:36px;object-fit:cover;border-radius:4px;flex-shrink:0"><span class="tbl-name">'+b.facilityName+'</span></div></td>'+
      '<td><div class="tbl-name">'+b.userName+'</div><div class="tbl-sub">'+b.userEmail+'</div></td>'+
      '<td><div>'+formatDate(b.date)+'</div><div class="tbl-sub">'+b.time+'</div></td>'+
      '<td>'+b.duration+'h</td>'+
      '<td><span class="status-badge '+b.status+'">'+b.status+'</span></td>'+
      '<td>'+actions+'</td>'+
    '</tr>';
  }).join('');


function adminSetBookingStatus(id, status){
  const endpoint = status === 'approved'
    ? '/api/admin/bookings/'+id+'/approve'
    : '/api/admin/bookings/'+id+'/reject';

  fetch(endpoint, {method: 'POST'})
  .then(r => r.json())
  .then(data => {
    if(data.error){ alert(data.error); return; }
    showCrudToast('Booking ' + status + '.');
    renderAdminBookings();
    renderAdminDashboard();
    renderBookingList();
  })
  .catch(() => alert('Server error. Try again.'));
}

/* ── USERS PANEL ── */
function renderUsersTable(){
  var users = getUsers();
  var q = (document.getElementById('userSearch')||{value:''}).value.toLowerCase();
  var filtered = users.filter(function(u){
    return (u.fname+' '+u.lname).toLowerCase().includes(q) ||
      u.email.toLowerCase().includes(q) ||
      u.role.toLowerCase().includes(q);
  });
  document.getElementById('usersCount').textContent = '('+filtered.length+')';
  if(!filtered.length){
    document.getElementById('usersTableBody').innerHTML =
      '<tr><td colspan="6" style="text-align:center;color:var(--muted);padding:28px">No users found.</td></tr>';
    return;
  }
  document.getElementById('usersTableBody').innerHTML = filtered.map(function(u,i){
    var joined = new Date(u.createdAt).toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'});
    var isProtected = (u.id==='u_admin');
    var initials = u.fname[0].toUpperCase()+u.lname[0].toUpperCase();
    var actions = isProtected
      ? '<span style="color:var(--muted);font-size:11px">Protected</span>'
      : '<button class="action-edit" onclick="editUser(\'' + u.id + '\')" >Edit</button>'+
        '<button class="action-delete" onclick="openDeleteModal(\'' + u.id + '\')" >Delete</button>';
    return '<tr style="animation:slideIn .25s ease '+(i*.04)+'s both">'+
      '<td><div style="display:flex;align-items:center;gap:10px">'+
        '<div style="width:34px;height:34px;border-radius:50%;background:linear-gradient(135deg,var(--accent),#0077ff);display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:700;color:var(--bg);flex-shrink:0">'+initials+'</div>'+
        '<div class="tbl-name">'+u.fname+' '+u.lname+'</div></div></td>'+
      '<td>'+u.email+'</td>'+
      '<td>'+(u.phone||'—')+'</td>'+
      '<td><span class="status-badge '+(u.role==='admin'?'confirmed':'pending')+'">'+u.role+'</span></td>'+
      '<td style="color:var(--muted);font-size:12px">'+joined+'</td>'+
      '<td>'+actions+'</td>'+
    '</tr>';
  }).join('');
}

function resetCrudForm(){
  document.getElementById('cu-fname').value='';
  document.getElementById('cu-lname').value='';
  document.getElementById('cu-email').value='';
  document.getElementById('cu-phone').value='';
  document.getElementById('cu-password').value='';
  document.getElementById('cu-password').placeholder='Min. 6 characters';
  document.getElementById('cu-role').value='user';
  document.getElementById('cu-editing-id').value='';
  document.getElementById('crudTitle').textContent='Add New User';
  document.getElementById('crudSubmitBtn').textContent='Add User';
  document.getElementById('crudCloseBtn').style.display='none';
  document.getElementById('cu-pw-hint').textContent='';
  ['fname','lname','email','password'].forEach(function(f){
    document.getElementById('cu-err-'+f).classList.remove('show');
    document.getElementById('cu-'+f).classList.remove('err');
  });
}

function editUser(id){
  var u=getUsers().find(function(x){return x.id===id;});
  if(!u) return;
  document.getElementById('cu-fname').value=u.fname;
  document.getElementById('cu-lname').value=u.lname;
  document.getElementById('cu-email').value=u.email;
  document.getElementById('cu-phone').value=u.phone||'';
  document.getElementById('cu-password').value='';
  document.getElementById('cu-password').placeholder='Leave blank to keep current';
  document.getElementById('cu-role').value=u.role;
  document.getElementById('cu-editing-id').value=u.id;
  document.getElementById('crudTitle').textContent='Edit User';
  document.getElementById('crudSubmitBtn').textContent='Save Changes';
  document.getElementById('crudCloseBtn').style.display='';
  document.getElementById('cu-pw-hint').textContent='(leave blank to keep current)';
  document.getElementById('crudCard').scrollIntoView({behavior:'smooth',block:'start'});
}

function submitCrudUser(){
  var fname=document.getElementById('cu-fname').value.trim();
  var lname=document.getElementById('cu-lname').value.trim();
  var email=document.getElementById('cu-email').value.trim();
  var phone=document.getElementById('cu-phone').value.trim();
  var pw=document.getElementById('cu-password').value;
  var role=document.getElementById('cu-role').value;
  var editingId=document.getElementById('cu-editing-id').value;
  var isEditing=!!editingId;
  var ok=true;
  function setErr(f,v){document.getElementById('cu-err-'+f).classList.toggle('show',v);document.getElementById('cu-'+f).classList.toggle('err',v);}
  if(!fname){setErr('fname',true);ok=false;}else setErr('fname',false);
  if(!lname){setErr('lname',true);ok=false;}else setErr('lname',false);
  if(!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)){setErr('email',true);ok=false;}else setErr('email',false);
  if(!isEditing&&pw.length<6){setErr('password',true);ok=false;}
  else if(isEditing&&pw&&pw.length<6){setErr('password',true);ok=false;}
  else setErr('password',false);
  if(!ok) return;
  var users=getUsers();
  var dup=users.find(function(u){return u.email===email&&u.id!==editingId;});
  if(dup){document.getElementById('cu-err-email').textContent='Email already registered.';setErr('email',true);return;}
  document.getElementById('cu-err-email').textContent='Valid email required.';
  if(isEditing){
    var idx=users.findIndex(function(u){return u.id===editingId;});
    if(idx===-1) return;
    users[idx].fname=fname;users[idx].lname=lname;users[idx].email=email;users[idx].phone=phone;users[idx].role=role;
    if(pw) users[idx].password=pw;
    saveUsers(users);
    if(currentUser&&currentUser.id===editingId){
      currentUser=users[idx];saveSession(currentUser);
      document.getElementById('userAvatar').textContent=currentUser.fname[0].toUpperCase();
      document.getElementById('userName').textContent=currentUser.fname+' '+currentUser.lname;
    }
    showCrudToast('User updated successfully.');
  } else {
    users.push({id:'u_'+Date.now(),email:email,password:pw,fname:fname,lname:lname,phone:phone,role:role,createdAt:new Date().toISOString()});
    saveUsers(users);
    showCrudToast('User created successfully.');
  }
  resetCrudForm();
  renderUsersTable();
}

function openDeleteModal(id){_deletingUserId=id;document.getElementById('deleteModal').classList.add('show');}
function closeDeleteModal(){document.getElementById('deleteModal').classList.remove('show');_deletingUserId=null;}
function confirmDeleteUser(){
  if(!_deletingUserId) return;
  saveUsers(getUsers().filter(function(u){return u.id!==_deletingUserId;}));
  saveBookings(getBookings().filter(function(b){return b.userId!==_deletingUserId;}));
  closeDeleteModal();
  renderAdminDashboard();
  updateStats();
  showCrudToast('User deleted.');
}

function showCrudToast(msg){
  var t=document.getElementById('crudToast');
  if(!t){
    t=document.createElement('div');t.id='crudToast';
    t.style.cssText='position:fixed;bottom:32px;right:32px;background:var(--green);color:#000;padding:12px 22px;border-radius:8px;font-size:13px;font-weight:600;z-index:9999;opacity:0;transition:opacity .3s;font-family:var(--font-b);box-shadow:0 4px 20px rgba(0,0,0,.4)';
    document.body.appendChild(t);
  }
  t.textContent=msg;t.style.opacity='1';
  clearTimeout(t._timer);
  t._timer=setTimeout(function(){t.style.opacity='0';},2800);
}

/* Stats */
function updateStats(){
  if(!currentUser) return;
  if(currentUser.role === 'admin'){
    fetch('/api/admin/stats')
    .then(r => r.json())
    .then(data => {
      if(data.error) return;
      document.getElementById('stat-bookings').textContent = data.total_bookings;
      document.getElementById('stat-avail').textContent   = data.total_facilities;
    });
  } else {
    fetch('/api/bookings')
    .then(r => r.json())
    .then(bookings => {
      if(!Array.isArray(bookings)) return;
      document.getElementById('stat-bookings').textContent = bookings.filter(b => b.status === 'approved').length;
    });
  }
}

/* Utils */
function todayStr(){return new Date().toISOString().split('T')[0]}
function formatDate(s){
 if(!s) return'—';
 const d=new Date(s+'T00:00:00');
 return d.toLocaleDateString('en-US',{weekday:'short',month:'short',day:'numeric',year:'numeric'});
}
function showPage(name,btn){
 document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
 document.querySelectorAll('.nav-btn').forEach(b=>b.classList.remove('active'));
 document.getElementById('page-'+name).classList.add('active');
 if(btn) btn.classList.add('active');
 if(name==='mybookings') renderBookingList();
 if(name==='admin') renderAdminDashboard();
}
function closeModal(){document.getElementById('modalOverlay').classList.remove('show')}
